w_1 + w_2 = a, \
-w_1 + w_2 = b, \
w_1, w_2 \geq 0.
\end{cases}
$$
B. 	ext{max } w_1 + 2w_2

$$
	ext{s.t. }
 egin{cases}
w_1 - w_2 = a, \
w_1 + w_2 = b, \
w_1, w_2 \geq 0.
\end{cases}
$$
C. 	ext{min } 2w_1 + w_2

$$
	ext{s.t. }
 egin{cases}
w_1 - w_2 = a, \
 -w_1 + w_2 = b, \
w_1, w_2 \leq 0.
\end{cases}
$$
D. All other answers are incorrect
E. 	ext{min } w_1 + 2w_2

$$
	ext{s.t. }
 egin{cases}
w_1 - w_2 = a, \
 -w_1 + w_2 \geq b, \
w_1, w_2 \geq 0.
\end{cases}
$$
